import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface OrderData {
  order: {
    orderId: string;
    status: string;
    estimatedDelivery: string;
    lastUpdated: string;
  };
  deliveryProgress: {
    checkpoint: string;
    timestamp: string;
  }[];
  progressTrend: {
    date: string;
    progress: number;
  }[];
}

export default function Widget() {
  const data = response.data as OrderData;
  const { order, deliveryProgress, progressTrend } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Order ID: {order.orderId}
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#4CAF50' }}>
              Status: {order.status}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Estimated Delivery: {order.estimatedDelivery}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Last Updated: {new Date(order.lastUpdated).toLocaleString()}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {deliveryProgress.map((progress, index) => (
              <Chip key={index} label={progress.checkpoint} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
            ))}
          </Stack>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: progressTrend.map(pt => pt.progress),
                  color: '#FF5722',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: progressTrend.map(pt => new Date(pt.date).toLocaleDateString()),
                  id: 'dates',
                },
              ]}
              yAxis={[{ id: 'progress', min: 0, max: 100 }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="dates"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="progress"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
